import React from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import './LibraryPage.css';

const libraryItems = [
  { id: 1, title: 'Berserk', progress: 'Chapter 220/363', updatedAt: '2 hours ago' },
  { id: 2, title: 'Solo Leveling', progress: 'Chapter 95/179', updatedAt: 'Yesterday' },
  { id: 3, title: 'Tower of God', progress: 'Chapter 510/560', updatedAt: '3 days ago' }
];

const LibraryPage = () => {
  const { user } = useAuth();

  if (!user) {
    return (
      <div className="library-page">
        <h2>Login required</h2>
        <p>You need to sign in to view your library.</p>
      </div>
    );
  }

  return (
    <div className="library-page">
      <div className="library-header">
        <h1>My Library</h1>
        <p>Continue where you left off.</p>
      </div>
      <div className="library-grid">
        {libraryItems.map((item) => (
          <div key={item.id} className="library-card">
            <h3>{item.title}</h3>
            <p>{item.progress}</p>
            <span>Last update: {item.updatedAt}</span>
            <Link to={`/content/${item.id}`} className="open-btn">
              Open
            </Link>
          </div>
        ))}
      </div>
    </div>
  );
};

export default LibraryPage;
